INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025002, 'enem-2025-d1-azul-en-002', 2025, 1, 'azul', 2, 'en', 'Linguagens', 'Prova oficial ENEM 2025', 'My idea of philosophy is that if it is not relevant to human problems, if it does not tell us how we can go about eradicating some of the misery in this world, then it is not worth the name of philosophy. I think Socrates made a very profound statement when he asserted that philosophy is to teach us proper living. In this day and age “proper living” means liberation from the urgent problems of poverty, economic necessity and indoctrination, mental oppression.DAVIS, A. Lectures on Liberation. Washington: Smithsonian Libraries, 1971 (adaptado).Nesse texto, ao discorrer sobre a relevância da filosofia, a escritora Angela Davis tem por objetivo', '[{"type":"text","content":"My idea of philosophy is that if it is not relevant to human problems, if it does not tell us how we can go about eradicating some of the misery in this world, then it is not worth the name of philosophy. I think Socrates made a very profound statement when he asserted that philosophy is to teach us proper living. In this day and age “proper living” means liberation from the urgent problems of poverty, economic necessity and indoctrination, mental oppression.DAVIS, A. Lectures on Liberation. Washington: Smithsonian Libraries, 1971 (adaptado).Nesse texto, ao discorrer sobre a relevância da filosofia, a escritora Angela Davis tem por objetivo"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
--> statement-breakpoint
