INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025006, 'enem-2025-d1-azul-es-001', 2025, 1, 'azul', 1, 'es', 'Linguagens', 'Prova oficial ENEM 2025', '¿Dónde está nuestro pan, patrón?¿Dónde quedó todo ese dinero?¿Lo tiene oculto bajo el colchóno lo escondió en otro sucio agujero?Yo tengo un Tàpies, dice Juan Luis;yo tengo un Antonio López, dice Jaume.¿Quién de los dos sabrá decircuántos muertos tiene a sus espaldas?NACHO VEGAS. Disponível em: www.lahiguera.net. Acesso em: 12 abr. 2024 (fragmento).Na letra da canção Polvorado, ao apresentar as reflexões do eu poético, o cantor espanhol Nacho Vegas', '[{"type":"text","content":"¿Dónde está nuestro pan, patrón?¿Dónde quedó todo ese dinero?¿Lo tiene oculto bajo el colchóno lo escondió en otro sucio agujero?Yo tengo un Tàpies, dice Juan Luis;yo tengo un Antonio López, dice Jaume.¿Quién de los dos sabrá decircuántos muertos tiene a sus espaldas?NACHO VEGAS. Disponível em: www.lahiguera.net. Acesso em: 12 abr. 2024 (fragmento).Na letra da canção Polvorado, ao apresentar as reflexões do eu poético, o cantor espanhol Nacho Vegas"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
