INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025017, 'enem-2025-d1-azul-shared-012', 2025, 1, 'azul', 12, NULL, 'Linguagens', 'Prova oficial ENEM 2025', 'O Ministério do Esporte no Brasil lançou o programa Maré Inclusiva, em 2024, ano dos Jogos Paralímpicos de Paris. Esse programa visa ampliar as oportunidades para pessoas com deficiência que desejam praticar o surf. O parasurf é a prática do surf adaptada para permitir que pessoas com deficiência pratiquem o esporte em todas as suas categorias, modalidades e manifestações. Para a Secretaria Nacional do Paradesporto, a iniciativa é mais do que um programa de esporte, é uma iniciativa que busca transformar vidas e promover a inclusão por meio do parasurf, criando um legado de igualdade e respeito.Disponível em: www.gov.br/esporte. Acesso em: 6 set. 2024 (adaptado).De acordo com esse texto, o programa voltado ao estímulo da prática do parasurf evidencia a', '[{"type":"text","content":"O Ministério do Esporte no Brasil lançou o programa Maré Inclusiva, em 2024, ano dos Jogos Paralímpicos de Paris. Esse programa visa ampliar as oportunidades para pessoas com deficiência que desejam praticar o surf. O parasurf é a prática do surf adaptada para permitir que pessoas com deficiência pratiquem o esporte em todas as suas categorias, modalidades e manifestações. Para a Secretaria Nacional do Paradesporto, a iniciativa é mais do que um programa de esporte, é uma iniciativa que busca transformar vidas e promover a inclusão por meio do parasurf, criando um legado de igualdade e respeito.Disponível em: www.gov.br/esporte. Acesso em: 6 set. 2024 (adaptado).De acordo com esse texto, o programa voltado ao estímulo da prática do parasurf evidencia a"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
