INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025021, 'enem-2025-d1-azul-shared-016', 2025, 1, 'azul', 16, NULL, 'Linguagens', 'Prova oficial ENEM 2025', 'SímbolosEu e tu, ante a noite e o amplo desdobramentodo mar, fero, a estourar de encontro à rocha nua...Um símbolo descubro aqui, neste momentoesta rocha, este mar... a minha vida e a tua.O mar vem, o mar vai, nele há o gesto violentode quem maltrata e, após, se arrepende e recua.Como compreendo bem da rocha o sentimento!São muito iguais, por certo, a minha mágoa e a sua.Contemplo neste quadro a nossa triste vida;tu és dúbio mar que, na sua inconsciência,tem carinhos de amor e fúrias de demência!Eu sou a dor estanque, a dor empedernida,sou rocha a emergir de um côncavo de areia,imóvel, muda, isenta e alheia ao mar, alheia.MACHADO, G. Poesia completa. Rio de Janeiro: Cátedra/MEC, 1978.Nesse soneto, os traços da estética simbolista são resgatados pelo eu lírico ao', '[{"type":"text","content":"SímbolosEu e tu, ante a noite e o amplo desdobramentodo mar, fero, a estourar de encontro à rocha nua...Um símbolo descubro aqui, neste momentoesta rocha, este mar... a minha vida e a tua.O mar vem, o mar vai, nele há o gesto violentode quem maltrata e, após, se arrepende e recua.Como compreendo bem da rocha o sentimento!São muito iguais, por certo, a minha mágoa e a sua.Contemplo neste quadro a nossa triste vida;tu és dúbio mar que, na sua inconsciência,tem carinhos de amor e fúrias de demência!Eu sou a dor estanque, a dor empedernida,sou rocha a emergir de um côncavo de areia,imóvel, muda, isenta e alheia ao mar, alheia.MACHADO, G. Poesia completa. Rio de Janeiro: Cátedra/MEC, 1978.Nesse soneto, os traços da estética simbolista são resgatados pelo eu lírico ao"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
