INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025028, 'enem-2025-d1-azul-shared-023', 2025, 1, 'azul', 23, NULL, 'Linguagens', 'Prova oficial ENEM 2025', 'TEXTO IOs trabalhos da exposição Adriana Varejão: suturas, fissuras, ruínas colocam em pauta o exame da história visual, das tradições iconográficas europeias e do fazer artístico ocidental. O corte, a rachadura, o talho e a fissura são elementos de narrativas recorrentes nos trabalhos da artista desde 1992. As produções recentes incluem pinturas tridimensionais de grande escala das séries Ruínas de charque e Línguas.Disponível em: https://pinacoteca.org.br. Acesso em: 10 jan. 2025 (adaptado).TEXTO II VAREJÃO, A. Azulejaria em carne viva. Óleo sobre tela, poliuretano, madeira e alumínio, 160 × 200 × 25 cm. 1999.Disponível em: www.adrianavarejao.net. Acesso em: 10 jan. 2025.A utilização de recursos visuais como suturas, cortes e ruínas por Adriana Varejão, na obra Azulejaria em carne viva, remete à(s)', '[{"type":"text","content":"TEXTO IOs trabalhos da exposição Adriana Varejão: suturas, fissuras, ruínas colocam em pauta o exame da história visual, das tradições iconográficas europeias e do fazer artístico ocidental. O corte, a rachadura, o talho e a fissura são elementos de narrativas recorrentes nos trabalhos da artista desde 1992. As produções recentes incluem pinturas tridimensionais de grande escala das séries Ruínas de charque e Línguas.Disponível em: https://pinacoteca.org.br. Acesso em: 10 jan. 2025 (adaptado).TEXTO II"},{"type":"image","content":"/enem/2025/dia1/question-23.png"},{"type":"text","content":"VAREJÃO, A. Azulejaria em carne viva. Óleo sobre tela, poliuretano, madeira e alumínio, 160 × 200 × 25 cm. 1999.Disponível em: www.adrianavarejao.net. Acesso em: 10 jan. 2025.A utilização de recursos visuais como suturas, cortes e ruínas por Adriana Varejão, na obra Azulejaria em carne viva, remete à(s)"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', '/enem/2025/dia1/question-23.png', 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
