INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025033, 'enem-2025-d1-azul-shared-028', 2025, 1, 'azul', 28, NULL, 'Linguagens', 'Prova oficial ENEM 2025', 'Pequenino mortoTange o sino, tange, numa voz de choro,Numa voz de choro... tão desconsolado...No caixão dourado, como em berço de ouro,Pequenino, levam-te dormindo... Acorda!Olha que te levam para o mesmo ladoDe onde o sino tange numa voz de choro...Pequenino, acorda!Que caminho triste, e que viagem! AlasDe ciprestes negros a gemer no vento;Tanta boca aberta de famintas valasA pedir que as fartem, a esperar que as encham...Pequenino, acorda! Recupera o alento,Foge da cobiça dessas fundas valasA pedir que as encham.CARVALHO, V. Poemas e canções. Rio de Janeiro: Saraiva, 1962 (fragmento).Nesse fragmento do poema, o sentimento de luto adquire contornos expressivos e é intensificado pela', '[{"type":"text","content":"Pequenino mortoTange o sino, tange, numa voz de choro,Numa voz de choro... tão desconsolado...No caixão dourado, como em berço de ouro,Pequenino, levam-te dormindo... Acorda!Olha que te levam para o mesmo ladoDe onde o sino tange numa voz de choro...Pequenino, acorda!Que caminho triste, e que viagem! AlasDe ciprestes negros a gemer no vento;Tanta boca aberta de famintas valasA pedir que as fartem, a esperar que as encham...Pequenino, acorda! Recupera o alento,Foge da cobiça dessas fundas valasA pedir que as encham.CARVALHO, V. Poemas e canções. Rio de Janeiro: Saraiva, 1962 (fragmento).Nesse fragmento do poema, o sentimento de luto adquire contornos expressivos e é intensificado pela"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
