INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025043, 'enem-2025-d1-azul-shared-038', 2025, 1, 'azul', 38, NULL, 'Linguagens', 'Prova oficial ENEM 2025', '123456789O mais assustador do meteoro que cruzou o céu da Sibéria e explodiu no ar como várias bombas atômicas é que ele chegou sem ser anunciado. Com todas as atenções voltadas para o outro asteroide, o que passou de raspão, o asteroide da Sibéria entrou pela porta dos fundos sem ser detectado. A desculpa é que era pequeno demais para chamar a atenção e por isso os alarmes não funcionaram. Nossa ilusão, até agora, era que qualquer detrito espacial que se aproximasse de nós seria identificado e rotulado, e sua trajetória calculada até o último milímetro com grande antecedência, o que nos daria tempo para preparar o espírito — ou usar nossos cartões de crédito até o limite — no caso da colisão com a Terra ser inevitável.VERISSIMO, L. F. Disponível em: www.estadao.com.br. Acesso em: 1 mar. 2013.Com base na organização coesiva desse texto, o(a)', '[{"type":"text","content":"123456789O mais assustador do meteoro que cruzou o céu da Sibéria e explodiu no ar como várias bombas atômicas é que ele chegou sem ser anunciado. Com todas as atenções voltadas para o outro asteroide, o que passou de raspão, o asteroide da Sibéria entrou pela porta dos fundos sem ser detectado. A desculpa é que era pequeno demais para chamar a atenção e por isso os alarmes não funcionaram. Nossa ilusão, até agora, era que qualquer detrito espacial que se aproximasse de nós seria identificado e rotulado, e sua trajetória calculada até o último milímetro com grande antecedência, o que nos daria tempo para preparar o espírito — ou usar nossos cartões de crédito até o limite — no caso da colisão com a Terra ser inevitável.VERISSIMO, L. F. Disponível em: www.estadao.com.br. Acesso em: 1 mar. 2013.Com base na organização coesiva desse texto, o(a)"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
