INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025046, 'enem-2025-d1-azul-shared-041', 2025, 1, 'azul', 41, NULL, 'Linguagens', 'Prova oficial ENEM 2025', 'TEXTO IOrigem, tradição e resistênciaFoi sentada em seu banco de quartzo que a avó do universo, moradora da Maloca do Céu, criou os homens, os animais, a terra e as águas. O banco foi entregue aos ancestrais dos atuais Tukano, que passaram a reproduzi-lo em madeira. O mito Tukano — povo do noroeste da Amazônia que ainda hoje fabrica os bancos em seu estilo tradicional — indica o lugar dos bancos entre os objetos sagrados, ao mesmo tempo parte do universo primitivo e fonte do poder de criação. A presença nos mitos de origem de alguns povos atesta a antiguidade da arte de talhar bancos: os primeiros registros do uso desses objetos entre ameríndios das terras baixas da América do Sul, do Caribe e da América Central datam de, pelo menos, 4 mil anos.ASSIS, R.; MENDES JR., L. Bancos indígenas do Brasil. São Paulo: BEI Comunicação, 2013.TEXTO II KAMAYURÁ, Y. Tatu Kamayurá1. Madeira, 61 × 24 × 20 cm. Xingu (MT), s.d.Disponível em: www.colecaobei.com.br. Acesso em: 15 out. 2024.Os textos I e ll demonstram, na confecção dos bancos, uma íntima relação de sacralidade entre o ser humano e a natureza, perceptível por meio da', '[{"type":"text","content":"TEXTO IOrigem, tradição e resistênciaFoi sentada em seu banco de quartzo que a avó do universo, moradora da Maloca do Céu, criou os homens, os animais, a terra e as águas. O banco foi entregue aos ancestrais dos atuais Tukano, que passaram a reproduzi-lo em madeira. O mito Tukano — povo do noroeste da Amazônia que ainda hoje fabrica os bancos em seu estilo tradicional — indica o lugar dos bancos entre os objetos sagrados, ao mesmo tempo parte do universo primitivo e fonte do poder de criação. A presença nos mitos de origem de alguns povos atesta a antiguidade da arte de talhar bancos: os primeiros registros do uso desses objetos entre ameríndios das terras baixas da América do Sul, do Caribe e da América Central datam de, pelo menos, 4 mil anos.ASSIS, R.; MENDES JR., L. Bancos indígenas do Brasil. São Paulo: BEI Comunicação, 2013.TEXTO II"},{"type":"image","content":"/enem/2025/dia1/question-41.png"},{"type":"text","content":"KAMAYURÁ, Y. Tatu Kamayurá1. Madeira, 61 × 24 × 20 cm. Xingu (MT), s.d.Disponível em: www.colecaobei.com.br. Acesso em: 15 out. 2024.Os textos I e ll demonstram, na confecção dos bancos, uma íntima relação de sacralidade entre o ser humano e a natureza, perceptível por meio da"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', '/enem/2025/dia1/question-41.png', 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
