INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025047, 'enem-2025-d1-azul-shared-042', 2025, 1, 'azul', 42, NULL, 'Linguagens', 'Prova oficial ENEM 2025', 'TRADUZINDO O JURIDIQUÊS“Denego a liminar pleiteada na exordial, inobstante após a oitiva da parte adversa e da dilação probatória possa lograr alcançar um outro epílogo para o deslinde da quaestio sub examine.”TRADUÇãONão atendo, por ora, a liminar requerida na petição inicial, ainda que possa chegar a uma outra conclusão após ouvir a outra parte e avaliar as provas produzidas.Proposta de emenda à Constituição 269 de 2013. Aplica-se aos Governadores e Prefeitos o Regime Geral de Previdência Social, vedada a concessão graciosa, após o término do mandato, de vantagem pecuniária, verba de representação, pensão ou subsídio.TRADUÇãOTorna-se proibido pagar benefícios vitalícios para ex-prefeitos e ex-governadores.Superinteressante, n. 322, ago. 2013 (adaptado).Nesse texto, contribui para a construção da ironia a tradução das passagens escritas em “juridiquês” para uma variedade', '[{"type":"text","content":"TRADUZINDO O JURIDIQUÊS“Denego a liminar pleiteada na exordial, inobstante após a oitiva da parte adversa e da dilação probatória possa lograr alcançar um outro epílogo para o deslinde da quaestio sub examine.”TRADUÇãONão atendo, por ora, a liminar requerida na petição inicial, ainda que possa chegar a uma outra conclusão após ouvir a outra parte e avaliar as provas produzidas.Proposta de emenda à Constituição 269 de 2013. Aplica-se aos Governadores e Prefeitos o Regime Geral de Previdência Social, vedada a concessão graciosa, após o término do mandato, de vantagem pecuniária, verba de representação, pensão ou subsídio.TRADUÇãOTorna-se proibido pagar benefícios vitalícios para ex-prefeitos e ex-governadores.Superinteressante, n. 322, ago. 2013 (adaptado).Nesse texto, contribui para a construção da ironia a tradução das passagens escritas em “juridiquês” para uma variedade"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
