INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025049, 'enem-2025-d1-azul-shared-044', 2025, 1, 'azul', 44, NULL, 'Linguagens', 'Prova oficial ENEM 2025', 'Porque ler para crianças é um ato de amorParece que, com o avanço da tecnologia,os livros têm enfrentado cada vez mais concorrência. Por isso, é nossa função lembrara importância da leitura em todas as fases da vida, mas principalmente na primeira infância (entre 0 e 5 anos), quando o desenvolvimento das crianças acontece de forma mais intensa.O ato de ler com uma criança ou ler para ela vai muito além de apenas aproveitar uma história em conjunto. É um laço de amorosidade, porque oferece a ela ferramentas que vão ajudá-la a crescer forte e independente.Se você precisa de uma motivação extra para entrar nessa rede de incentivo, fique ligado nos motivos a seguir. Adotar esse hábito em casa:1 – cria um laço emocional com a criança;2 – ajuda no desenvolvimento das capacidades cognitivas;3 – ensina sobre o mundo;4 – incentiva o processamento de informações e a imaginação.Disponível em: www.huffpost.com.br. Acesso em: 22 maio 2018 (adaptado).Para persuadir o interlocutor sobre a importância de ler para as crianças, esse texto recorre à estratégia de', '[{"type":"text","content":"Porque ler para crianças é um ato de amorParece que, com o avanço da tecnologia,os livros têm enfrentado cada vez mais concorrência. Por isso, é nossa função lembrara importância da leitura em todas as fases da vida, mas principalmente na primeira infância (entre 0 e 5 anos), quando o desenvolvimento das crianças acontece de forma mais intensa.O ato de ler com uma criança ou ler para ela vai muito além de apenas aproveitar uma história em conjunto. É um laço de amorosidade, porque oferece a ela ferramentas que vão ajudá-la a crescer forte e independente.Se você precisa de uma motivação extra para entrar nessa rede de incentivo, fique ligado nos motivos a seguir. Adotar esse hábito em casa:1 – cria um laço emocional com a criança;2 – ajuda no desenvolvimento das capacidades cognitivas;3 – ensina sobre o mundo;4 – incentiva o processamento de informações e a imaginação.Disponível em: www.huffpost.com.br. Acesso em: 22 maio 2018 (adaptado).Para persuadir o interlocutor sobre a importância de ler para as crianças, esse texto recorre à estratégia de"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
