INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025065, 'enem-2025-d1-azul-shared-060', 2025, 1, 'azul', 60, NULL, 'Ciências Humanas', 'Prova oficial ENEM 2025', 'Adam Smith via o açougueiro e o padeiro não só como indivíduos buscando seus interesses financeiros, mas como pessoas moralmente motivadas dentro de uma sociedade. A base da moral era a empatia e o julgamento, instaurando uma distinção entre o que queremos fazer e o que sentimos que devemos fazer.COLLIER, P. O futuro do capitalismo. Porto Alegre: LP&M, 2019.O texto defende uma motivação capitalista para o campo dos negócios, na qual o lucro se mostra associado à', '[{"type":"text","content":"Adam Smith via o açougueiro e o padeiro não só como indivíduos buscando seus interesses financeiros, mas como pessoas moralmente motivadas dentro de uma sociedade. A base da moral era a empatia e o julgamento, instaurando uma distinção entre o que queremos fazer e o que sentimos que devemos fazer.COLLIER, P. O futuro do capitalismo. Porto Alegre: LP&M, 2019.O texto defende uma motivação capitalista para o campo dos negócios, na qual o lucro se mostra associado à"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
