INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025076, 'enem-2025-d1-azul-shared-071', 2025, 1, 'azul', 71, NULL, 'Ciências Humanas', 'Prova oficial ENEM 2025', 'Moradores de Berlim protestaram contra a demolição de um trecho do muro que dividiu a cidade durante quase três décadas. Tratado como patrimônio cultural e histórico da cidade, o East Side Gallery, repleto de grafites emblemáticos, está na mira de uma construtora que pretende levantar um condomínio de luxo às margens do Rio Spree, que corta a cidade.ALMEIDA, R. Alemães impedem demolição de último trecho original do muro de Berlim.Disponível em: http://operamundi.uol.com.br. Acesso em: 2 fev. 2021 (adaptado).A demolição do símbolo histórico mencionado representa uma', '[{"type":"text","content":"Moradores de Berlim protestaram contra a demolição de um trecho do muro que dividiu a cidade durante quase três décadas. Tratado como patrimônio cultural e histórico da cidade, o East Side Gallery, repleto de grafites emblemáticos, está na mira de uma construtora que pretende levantar um condomínio de luxo às margens do Rio Spree, que corta a cidade.ALMEIDA, R. Alemães impedem demolição de último trecho original do muro de Berlim.Disponível em: http://operamundi.uol.com.br. Acesso em: 2 fev. 2021 (adaptado).A demolição do símbolo histórico mencionado representa uma"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
