INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025081, 'enem-2025-d1-azul-shared-076', 2025, 1, 'azul', 76, NULL, 'Ciências Humanas', 'Prova oficial ENEM 2025', 'Os direitos do homem constituem uma classe variável, como a história destes últimos séculos demonstra suficientemente. O elenco dos direitos do homem se modificou, e continua a se modificar, com a mudança das condições históricas, ou seja, dos carecimentos e dos interesses, das classes no poder, dos meios disponíveis para a realização dos mesmos, das transformações técnicas. Direitos que foram declarados absolutos no final do século XVIII foram submetidos a radicais limitações nas declarações contemporâneas; direitos que as declarações do século XVIII nem sequer mencionavam, como os direitos sociais, são agora proclamados com grande ostentação nas recentes declarações.BOBBIO, N. A era dos direitos. Rio de Janeiro: Elsevier, 2004.Os argumentos apresentados no texto sustentam que os direitos humanos são variáveis porque os considera como', '[{"type":"text","content":"Os direitos do homem constituem uma classe variável, como a história destes últimos séculos demonstra suficientemente. O elenco dos direitos do homem se modificou, e continua a se modificar, com a mudança das condições históricas, ou seja, dos carecimentos e dos interesses, das classes no poder, dos meios disponíveis para a realização dos mesmos, das transformações técnicas. Direitos que foram declarados absolutos no final do século XVIII foram submetidos a radicais limitações nas declarações contemporâneas; direitos que as declarações do século XVIII nem sequer mencionavam, como os direitos sociais, são agora proclamados com grande ostentação nas recentes declarações.BOBBIO, N. A era dos direitos. Rio de Janeiro: Elsevier, 2004.Os argumentos apresentados no texto sustentam que os direitos humanos são variáveis porque os considera como"}]', NULL, 'INEP · ENEM 2025 · 1º dia · Caderno 1 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D1_CD1.pdf', NULL, 'enem/2025/dia1', 'official', 'valid', 'published', 'imported', 1);
