INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025099, 'enem-2025-d2-azul-shared-094', 2025, 2, 'azul', 94, NULL, 'Ciências da Natureza', 'Prova oficial ENEM 2025', 'Réguas elétricas são dispositivos que permitem a ligação segura e simultânea de dois ou mais aparelhos eletroeletrônicos à rede elétrica. Uma estudante comprou uma régua com seis tomadas, conforme a figura. Essa régua suporta uma intensidade máxima de corrente elétrica igual a 20 A. Acima desse valor, o fusível de segurança da régua se rompe, inutilizando-a até que um novo fusível seja instalado. Considere as potências nominais de alguns aparelhos eletroeletrônicos apresentadas no quadro.AparelhoPotência (watt)Luminária de LED5Computador250Impressora a laser660Secador de cabelos750Cafeteira900Condicionador de ar portátil1 100 Em um dia quente, a estudante mantém o computador e o condicionador de ar portátil ligados à régua permanentemente. Nessa situação, ela tenta realizar algumas atividades, uma de cada vez, utilizando a mesma régua, na seguinte ordem:1º – imprimir um trabalho escolar;2º – fazer um café com a cafeteira;3º – ligar a luminária;4º – secar os cabelos.Sabe-se que a régua foi ligada à tensão elétrica de 110 V, adequada para o funcionamento desses aparelhos.Considerando a ordem das tentativas, quantas atividades a estudante conseguiu realizar sem queimar o fusível?', '[{"type":"text","content":"Réguas elétricas são dispositivos que permitem a ligação segura e simultânea de dois ou mais aparelhos eletroeletrônicos à rede elétrica. Uma estudante comprou uma régua com seis tomadas, conforme a figura. Essa régua suporta uma intensidade máxima de corrente elétrica igual a 20 A. Acima desse valor, o fusível de segurança da régua se rompe, inutilizando-a até que um novo fusível seja instalado. Considere as potências nominais de alguns aparelhos eletroeletrônicos apresentadas no quadro.AparelhoPotência (watt)Luminária de LED5Computador250Impressora a laser660Secador de cabelos750Cafeteira900Condicionador de ar portátil1 100"},{"type":"image","content":"/enem/2025/dia2/question-94.png"},{"type":"text","content":"Em um dia quente, a estudante mantém o computador e o condicionador de ar portátil ligados à régua permanentemente. Nessa situação, ela tenta realizar algumas atividades, uma de cada vez, utilizando a mesma régua, na seguinte ordem:1º – imprimir um trabalho escolar;2º – fazer um café com a cafeteira;3º – ligar a luminária;4º – secar os cabelos.Sabe-se que a régua foi ligada à tensão elétrica de 110 V, adequada para o funcionamento desses aparelhos.Considerando a ordem das tentativas, quantas atividades a estudante conseguiu realizar sem queimar o fusível?"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-94.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
