INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025102, 'enem-2025-d2-azul-shared-097', 2025, 2, 'azul', 97, NULL, 'Ciências da Natureza', 'Prova oficial ENEM 2025', 'A produção de vacinas exige uma sequência de procedimentos, além do cumprimento estrito de verificações de segurança. No esquema, estão demonstradas as etapas básicas realizadas para a fabricação de uma vacina utilizando a tecnologia tradicional e o efeito dela no organismo. O antígeno utilizado na vacina causa um efeito protetor contra o vírus porque', '[{"type":"text","content":"A produção de vacinas exige uma sequência de procedimentos, além do cumprimento estrito de verificações de segurança. No esquema, estão demonstradas as etapas básicas realizadas para a fabricação de uma vacina utilizando a tecnologia tradicional e o efeito dela no organismo."},{"type":"image","content":"/enem/2025/dia2/question-97.png"},{"type":"text","content":"O antígeno utilizado na vacina causa um efeito protetor contra o vírus porque"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-97.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
