INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025106, 'enem-2025-d2-azul-shared-101', 2025, 2, 'azul', 101, NULL, 'Ciências da Natureza', 'Prova oficial ENEM 2025', 'Por que os olhos ficam vermelhos em algumas fotografias?Em fotos tiradas com câmeras fotográficas antigas, por vezes as pessoas aparecem com os olhos vermelhos. Isso ocorre porque a luz do flash da câmera incide diretamente no globo ocular, sendo refletida por uma região repleta de vasos sanguíneos.Disponível em: www.uol.com.br. Acesso em: 14 jun. 2017 (adaptado).Esse efeito é mais comum à noite ou em lugares pouco iluminados porque, com a pupila', '[{"type":"text","content":"Por que os olhos ficam vermelhos em algumas fotografias?Em fotos tiradas com câmeras fotográficas antigas, por vezes as pessoas aparecem com os olhos vermelhos. Isso ocorre porque a luz do flash da câmera incide diretamente no globo ocular, sendo refletida por uma região repleta de vasos sanguíneos.Disponível em: www.uol.com.br. Acesso em: 14 jun. 2017 (adaptado).Esse efeito é mais comum à noite ou em lugares pouco iluminados porque, com a pupila"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', NULL, 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
