INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025117, 'enem-2025-d2-azul-shared-112', 2025, 2, 'azul', 112, NULL, 'Ciências da Natureza', 'Prova oficial ENEM 2025', 'Golden Rice, ou arroz dourado, é uma variedade de arroz enriquecida em betacaroteno, precursor da vitamina A. Foi desenvolvida para ajudar a combater a doença decorrente da deficiência dessa vitamina. Para a obtenção dessa variedade de arroz, foram utilizados métodos de engenharia genética.BORÉM, A.; SANTOS, F. R. Entendendo a biotecnologia.Viçosa: UFV, 2008 (adaptado).Esse alimento contribui para diminuir a carência associada a qual doença?', '[{"type":"text","content":"Golden Rice, ou arroz dourado, é uma variedade de arroz enriquecida em betacaroteno, precursor da vitamina A. Foi desenvolvida para ajudar a combater a doença decorrente da deficiência dessa vitamina. Para a obtenção dessa variedade de arroz, foram utilizados métodos de engenharia genética.BORÉM, A.; SANTOS, F. R. Entendendo a biotecnologia.Viçosa: UFV, 2008 (adaptado).Esse alimento contribui para diminuir a carência associada a qual doença?"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', NULL, 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
