INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025122, 'enem-2025-d2-azul-shared-117', 2025, 2, 'azul', 117, NULL, 'Ciências da Natureza', 'Prova oficial ENEM 2025', 'Para a produção de titânio metálico ou dióxido de titânio puros, é necessário fazer a cloração do minério que contém dióxido de titânio, com o objetivo de separar esse óxido de outras substâncias presentes no minério. A principal reação química de cloração é representada por:TiO2 (s) + 2 Cl2 (g) TiCl4 (g) + O2 (g) ΔH =+175 kJ/molDepois da cloração, o tetracloreto de titânio é condensado e convertido, novamente, a dióxido de titânio.Após o sistema atingir o equilíbrio químico, como a formação do TiCl4 pode ser favorecida?', '[{"type":"text","content":"Para a produção de titânio metálico ou dióxido de titânio puros, é necessário fazer a cloração do minério que contém dióxido de titânio, com o objetivo de separar esse óxido de outras substâncias presentes no minério. A principal reação química de cloração é representada por:TiO2 (s) + 2 Cl2 (g) TiCl4 (g) + O2 (g) ΔH =+175 kJ/molDepois da cloração, o tetracloreto de titânio é condensado e convertido, novamente, a dióxido de titânio.Após o sistema atingir o equilíbrio químico, como a formação do TiCl4 pode ser favorecida?"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', NULL, 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
--> statement-breakpoint
