INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025130, 'enem-2025-d2-azul-shared-125', 2025, 2, 'azul', 125, NULL, 'Ciências da Natureza', 'Prova oficial ENEM 2025', 'Apaixonada por culinária e química, uma chefe de cozinha calculou que, para promover o crescimento adequado da massa durante o cozimento de um bolo a 180 °C (453 K) e 1,00 atm, ela precisaria utilizar uma quantidade de fermento químico suficiente para produzir um volume de gás igual a 4,00 L. Com esse objetivo, ela escolheu utilizar o bicarbonato de amônio, um composto que, sob aquecimento, degrada-se em três gases distintos, que são os responsáveis pelo crescimento da massa. A decomposição do bicarbonato de amônio ocorre conforme a equação química apresentada e, nas condições do cozimento, seu rendimento é de 80%.NH4HCO3 (s) → NH3 (g) + CO2 (g) + H2O (g)Considere que a mistura dos gases se comporta como gás ideal nas condições de cozimento utilizadas pela chefe.Dados: Massa molar do NH4HCO3 = 79 g ⋅ mol−1 e R = 0,082 atm ⋅ L ⋅ mol−1⋅ K−1.A massa, em grama, de bicarbonato de amônio que ela deve utilizar é mais próxima de', '[{"type":"text","content":"Apaixonada por culinária e química, uma chefe de cozinha calculou que, para promover o crescimento adequado da massa durante o cozimento de um bolo a 180 °C (453 K) e 1,00 atm, ela precisaria utilizar uma quantidade de fermento químico suficiente para produzir um volume de gás igual a 4,00 L. Com esse objetivo, ela escolheu utilizar o bicarbonato de amônio, um composto que, sob aquecimento, degrada-se em três gases distintos, que são os responsáveis pelo crescimento da massa. A decomposição do bicarbonato de amônio ocorre conforme a equação química apresentada e, nas condições do cozimento, seu rendimento é de 80%.NH4HCO3 (s) → NH3 (g) + CO2 (g) + H2O (g)Considere que a mistura dos gases se comporta como gás ideal nas condições de cozimento utilizadas pela chefe.Dados: Massa molar do NH4HCO3 = 79 g ⋅ mol−1 e R = 0,082 atm ⋅ L ⋅ mol−1⋅ K−1.A massa, em grama, de bicarbonato de amônio que ela deve utilizar é mais próxima de"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', NULL, 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
--> statement-breakpoint
