INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025132, 'enem-2025-d2-azul-shared-127', 2025, 2, 'azul', 127, NULL, 'Ciências da Natureza', 'Prova oficial ENEM 2025', 'Nos processos de transformação e reciclagem de recursos naturais, as velocidades das reações químicas são estudadas pela cinética química. Uma reação A → B é realizada na presença e na ausência de uma enzima, com todas as demais condições permanecendo inalteradas. Considere que, no gráfico da variação de energia ao longo dessa reação, a linha contínua representa o avanço da reação na ausência da enzima, e a linha pontilhada, na presença da enzima.O gráfico que representa a situação descrita é:', '[{"type":"text","content":"Nos processos de transformação e reciclagem de recursos naturais, as velocidades das reações químicas são estudadas pela cinética química. Uma reação A → B é realizada na presença e na ausência de uma enzima, com todas as demais condições permanecendo inalteradas. Considere que, no gráfico da variação de energia ao longo dessa reação, a linha contínua representa o avanço da reação na ausência da enzima, e a linha pontilhada, na presença da enzima.O gráfico que representa a situação descrita é:"},{"type":"image","content":"/enem/2025/dia2/question-127.png"},{"type":"image","content":"/enem/2025/dia2/question-127_1.png"},{"type":"image","content":"/enem/2025/dia2/question-127_2.png"},{"type":"image","content":"/enem/2025/dia2/question-127_3.png"},{"type":"image","content":"/enem/2025/dia2/question-127_4.png"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-127.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
