INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025133, 'enem-2025-d2-azul-shared-128', 2025, 2, 'azul', 128, NULL, 'Ciências da Natureza', 'Prova oficial ENEM 2025', 'A resistência de um fio de platina pode ser usada para medir temperaturas entre 0 °C e 100°C e já foi utilizada como referência para a escala internacional de temperatura. Para um sensor feito de platina, a relação entre a resistência e a temperatura pode ser descrita por uma equação do tipo R(T) = A +T, em que T é a temperatura e A e B são constantes. O gráfico apresenta a dependência da resistência em função da temperatura para cinco diferentes sensores. Os sensores que apresentam maior sensibilidade são', '[{"type":"text","content":"A resistência de um fio de platina pode ser usada para medir temperaturas entre 0 °C e 100°C e já foi utilizada como referência para a escala internacional de temperatura. Para um sensor feito de platina, a relação entre a resistência e a temperatura pode ser descrita por uma equação do tipo R(T) = A +T, em que T é a temperatura e A e B são constantes. O gráfico apresenta a dependência da resistência em função da temperatura para cinco diferentes sensores."},{"type":"image","content":"/enem/2025/dia2/question-128.png"},{"type":"text","content":"Os sensores que apresentam maior sensibilidade são"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-128.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
--> statement-breakpoint
