INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025134, 'enem-2025-d2-azul-shared-129', 2025, 2, 'azul', 129, NULL, 'Ciências da Natureza', 'Prova oficial ENEM 2025', 'O ácido úsnico é retirado de liquens e foi testado contra diversas espécies, conforme o quadro.TesteResultadoAedes aegypti (larvas)Baixa eficiênciaBacilo de KochMédia eficiênciaMoluscos aquáticos (adultos)Alta eficiênciaPernilongo (larvas)Média eficiênciaVermes platelmintosIneficienteO ácido úsnico mostrou-se mais indicado para o controle da', '[{"type":"text","content":"O ácido úsnico é retirado de liquens e foi testado contra diversas espécies, conforme o quadro.TesteResultadoAedes aegypti (larvas)Baixa eficiênciaBacilo de KochMédia eficiênciaMoluscos aquáticos (adultos)Alta eficiênciaPernilongo (larvas)Média eficiênciaVermes platelmintosIneficienteO ácido úsnico mostrou-se mais indicado para o controle da"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', NULL, 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
