INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025142, 'enem-2025-d2-azul-shared-137', 2025, 2, 'azul', 137, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'A reportagem de uma revista abordou o uso de redes sociais pelos internautas brasileiros. Alguns dos dados apurados pela reportagem estão apresentados no infográfico.Perfil dos brasileiros nas redes sociais Disponível em: http://revistagalileu.globo.com. Acesso em: 22 out. 2015 (adaptado).Segundo os dados do infográfico, ao se escolher aleatoriamente um internauta brasileiro no período ao qual se refere a reportagem, a probabilidade de ele ser um homem que acessa alguma rede social é', '[{"type":"text","content":"A reportagem de uma revista abordou o uso de redes sociais pelos internautas brasileiros. Alguns dos dados apurados pela reportagem estão apresentados no infográfico.Perfil dos brasileiros nas redes sociais"},{"type":"image","content":"/enem/2025/dia2/question-137.png"},{"type":"text","content":"Disponível em: http://revistagalileu.globo.com. Acesso em: 22 out. 2015 (adaptado).Segundo os dados do infográfico, ao se escolher aleatoriamente um internauta brasileiro no período ao qual se refere a reportagem, a probabilidade de ele ser um homem que acessa alguma rede social é"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-137.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
