INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025143, 'enem-2025-d2-azul-shared-138', 2025, 2, 'azul', 138, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'Em um jogo de computador, um cubo se encontra inicialmente posicionado conforme indicado na figura. Cada deslocamento efetuado por esse cubo se dá sempre em uma das direções definidas pelos três eixos coordenados. Ao se movimentar a partir da posição inicial, esse cubo se aproximou 3 unidades do plano yz, se afastou 5 unidades do plano xze se aproximou 4 unidades do plano xy.A figura que apresenta as projeções ortogonais desse cubo sobre os três planos coordenados, após efetuar as movimentações descritas, é', '[{"type":"text","content":"Em um jogo de computador, um cubo se encontra inicialmente posicionado conforme indicado na figura."},{"type":"image","content":"/enem/2025/dia2/question-138.png"},{"type":"text","content":"Cada deslocamento efetuado por esse cubo se dá sempre em uma das direções definidas pelos três eixos coordenados. Ao se movimentar a partir da posição inicial, esse cubo se aproximou 3 unidades do plano yz, se afastou 5 unidades do plano xze se aproximou 4 unidades do plano xy.A figura que apresenta as projeções ortogonais desse cubo sobre os três planos coordenados, após efetuar as movimentações descritas, é"},{"type":"image","content":"/enem/2025/dia2/question-138_1.png"},{"type":"image","content":"/enem/2025/dia2/question-138_2.png"},{"type":"image","content":"/enem/2025/dia2/question-138_3.png"},{"type":"image","content":"/enem/2025/dia2/question-138_4.png"},{"type":"image","content":"/enem/2025/dia2/question-138_5.png"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-138.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
