INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025148, 'enem-2025-d2-azul-shared-143', 2025, 2, 'azul', 143, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'Na cantina de uma escola, há cinco alimentos vendidos em pacotes com diferentes quantidades de porções.As informações nutricionais contidas nos rótulos desses produtos estão indicadas nas imagens. Uma estudante opta sempre pelo alimento com a menor quantidade total de sódio por pacote.Qual desses produtos deve ser o escolhido pela estudante?', '[{"type":"text","content":"Na cantina de uma escola, há cinco alimentos vendidos em pacotes com diferentes quantidades de porções.As informações nutricionais contidas nos rótulos desses produtos estão indicadas nas imagens."},{"type":"image","content":"/enem/2025/dia2/question-143.png"},{"type":"text","content":"Uma estudante opta sempre pelo alimento com a menor quantidade total de sódio por pacote.Qual desses produtos deve ser o escolhido pela estudante?"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-143.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
--> statement-breakpoint
