INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025154, 'enem-2025-d2-azul-shared-149', 2025, 2, 'azul', 149, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'A cúpula pentagonal giralongada é um poliedro de Johnson, cujas faces são polígonos regulares, mas que não é um poliedro de Platão, de Arquimedes, prisma ou antiprisma.As figuras apresentam esse poliedro em duas posições e uma de suas planificações. Quantos vértices tem esse poliedro?', '[{"type":"text","content":"A cúpula pentagonal giralongada é um poliedro de Johnson, cujas faces são polígonos regulares, mas que não é um poliedro de Platão, de Arquimedes, prisma ou antiprisma.As figuras apresentam esse poliedro em duas posições e uma de suas planificações."},{"type":"image","content":"/enem/2025/dia2/question-149.png"},{"type":"image","content":"/enem/2025/dia2/question-149_1.png"},{"type":"text","content":"Quantos vértices tem esse poliedro?"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-149.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
