INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025160, 'enem-2025-d2-azul-shared-155', 2025, 2, 'azul', 155, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'Dez casais fundaram um grupo de dança e decidiram constituir uma diretoria com três cargos: presidente, secretário e tesoureiro. Para maior representatividade, decidiu-se que no máximo uma pessoa por casal poderá ocupar um cargo nessa diretoria.Quantas diretorias diferentes podem ser constituídas por esses 10 casais?', '[{"type":"text","content":"Dez casais fundaram um grupo de dança e decidiram constituir uma diretoria com três cargos: presidente, secretário e tesoureiro. Para maior representatividade, decidiu-se que no máximo uma pessoa por casal poderá ocupar um cargo nessa diretoria.Quantas diretorias diferentes podem ser constituídas por esses 10 casais?"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', NULL, 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
