INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025165, 'enem-2025-d2-azul-shared-160', 2025, 2, 'azul', 160, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'Um recipiente tem um formato que faz com que, ao ser enchido de água com uma vazão constante, a distância da lâmina de água ao tampo da mesa, em centímetro, aumente em relação ao tempo T, em minuto, de acordo com uma função do tipo=k+ tg[p(T+m)],sendo os parâmetros k, p e m números reais, para T variando entre 0 e 4 minutos, conforme ilustrado na figura, na qual estão apresentadas assíntotas verticais da função tangente utilizada na definição de . A expressão algébrica que representa a relação entre e T é', '[{"type":"text","content":"Um recipiente tem um formato que faz com que, ao ser enchido de água com uma vazão constante, a distância da lâmina de água ao tampo da mesa, em centímetro, aumente em relação ao tempo T, em minuto, de acordo com uma função do tipo=k+ tg[p(T+m)],sendo os parâmetros k, p e m números reais, para T variando entre 0 e 4 minutos, conforme ilustrado na figura, na qual estão apresentadas assíntotas verticais da função tangente utilizada na definição de ."},{"type":"image","content":"/enem/2025/dia2/question-160.png"},{"type":"text","content":"A expressão algébrica que representa a relação entre e T é"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-160.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
