INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025169, 'enem-2025-d2-azul-shared-164', 2025, 2, 'azul', 164, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'O dono de uma embarcação deve partir do ponto P e chegar ao ponto R por meio de dois deslocamentos lineares e navegando a uma velocidade constante. Essa viagem será feita durante a noite, e como ele dispõe somente de uma bússola e de um relógio, planejou sua rota da seguinte forma:1º – partir do ponto P na direção 110 e navegar por 4 horas, alcançando um ponto Q;2º – partir do ponto Q na direção 90 e navegar por 2 horas, alcançando o ponto de destino R.No entanto, ao direcionar o barco para o primeiro deslocamento, o fez na direção 340, em vez de 110. Com isso, realizou os seguintes deslocamentos:1º – partiu do ponto P na direção 340 e navegou por 4 horas, alcançando um ponto S;2º – partiu do ponto S na direção 90 e navegou por 2 horas, alcançando o ponto T.A figura apresenta a bússola, a rota planejada e a rota executada. O dono da embarcação só percebeu o equívoco ao chegar ao ponto T. Com isso, agora ele precisa definir a direção e o tempo de navegação que lhe permita, partindo do ponto T, chegar ao ponto de destino R por meio de uma rota retilínea.Considere 0,64 como aproximação para cos 50°.A direção e o tempo aproximado de navegação que o dono da embarcação deve utilizar são, respectivamente,', '[{"type":"text","content":"O dono de uma embarcação deve partir do ponto P e chegar ao ponto R por meio de dois deslocamentos lineares e navegando a uma velocidade constante. Essa viagem será feita durante a noite, e como ele dispõe somente de uma bússola e de um relógio, planejou sua rota da seguinte forma:1º – partir do ponto P na direção 110 e navegar por 4 horas, alcançando um ponto Q;2º – partir do ponto Q na direção 90 e navegar por 2 horas, alcançando o ponto de destino R.No entanto, ao direcionar o barco para o primeiro deslocamento, o fez na direção 340, em vez de 110. Com isso, realizou os seguintes deslocamentos:1º – partiu do ponto P na direção 340 e navegou por 4 horas, alcançando um ponto S;2º – partiu do ponto S na direção 90 e navegou por 2 horas, alcançando o ponto T.A figura apresenta a bússola, a rota planejada e a rota executada."},{"type":"image","content":"/enem/2025/dia2/question-164.png"},{"type":"text","content":"O dono da embarcação só percebeu o equívoco ao chegar ao ponto T. Com isso, agora ele precisa definir a direção e o tempo de navegação que lhe permita, partindo do ponto T, chegar ao ponto de destino R por meio de uma rota retilínea.Considere 0,64 como aproximação para cos 50°.A direção e o tempo aproximado de navegação que o dono da embarcação deve utilizar são, respectivamente,"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-164.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
