INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025173, 'enem-2025-d2-azul-shared-168', 2025, 2, 'azul', 168, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'Em um país, a primeira etapa para obtenção da carteira de motorista é a contratação de três produtos:• pacote com 20 aulas teóricas;• pacote com 10 aulas práticas;• aluguel do veículo para realização das aulas práticas.Uma pessoa que pretende obter a carteira de motorista pesquisou o valor do aluguel do veículo e os valores de cada aula teórica e de cada aula prática em três autoescolas. O quadro apresenta esses valores.AutoescolaValor de cada aula teórica (R$)Valor de cada aula prática (R$)Aluguel do veículo (R$)I1080400II3050200III2040400Ela contratará os três produtos numa mesma autoescola de modo que o custo total nessa primeira etapa seja o menor possível.A autoescola que será contratada é a', '[{"type":"text","content":"Em um país, a primeira etapa para obtenção da carteira de motorista é a contratação de três produtos:• pacote com 20 aulas teóricas;• pacote com 10 aulas práticas;• aluguel do veículo para realização das aulas práticas.Uma pessoa que pretende obter a carteira de motorista pesquisou o valor do aluguel do veículo e os valores de cada aula teórica e de cada aula prática em três autoescolas. O quadro apresenta esses valores.AutoescolaValor de cada aula teórica (R$)Valor de cada aula prática (R$)Aluguel do veículo (R$)I1080400II3050200III2040400Ela contratará os três produtos numa mesma autoescola de modo que o custo total nessa primeira etapa seja o menor possível.A autoescola que será contratada é a"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', NULL, 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
