INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025174, 'enem-2025-d2-azul-shared-169', 2025, 2, 'azul', 169, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'A produtividade de soja em uma área cultivada é a média da quantidade de sacas de 50 quilogramas que são produzidas por hectare. O quadro apresenta a área cultivada e a produtividade de soja em certa propriedade, ao longo de cinco safras, com períodos de um ano, de 2011 a 2016.Safra11-1212-1313-1414-1515-16Área cultivada (hectare)200220250250200Produtividade (sacas de 50 kg por hectare)4030454550O gráfico de linhas que representa a produção de soja dessa propriedade, em tonelada, nessas cinco safras é', '[{"type":"text","content":"A produtividade de soja em uma área cultivada é a média da quantidade de sacas de 50 quilogramas que são produzidas por hectare. O quadro apresenta a área cultivada e a produtividade de soja em certa propriedade, ao longo de cinco safras, com períodos de um ano, de 2011 a 2016.Safra11-1212-1313-1414-1515-16Área cultivada (hectare)200220250250200Produtividade (sacas de 50 kg por hectare)4030454550O gráfico de linhas que representa a produção de soja dessa propriedade, em tonelada, nessas cinco safras é"},{"type":"image","content":"/enem/2025/dia2/question-169.png"},{"type":"image","content":"/enem/2025/dia2/question-169_1.png"},{"type":"image","content":"/enem/2025/dia2/question-169_2.png"},{"type":"image","content":"/enem/2025/dia2/question-169_3.png"},{"type":"image","content":"/enem/2025/dia2/question-169_4.png"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-169.png', 'enem/2025/dia2', 'official', '