INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025179, 'enem-2025-d2-azul-shared-174', 2025, 2, 'azul', 174, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'Um carro que custa 60 mil reais é comercializado por uma revendedora que oferece duas opções de pagamento, todas sem entrada e sem juros:• opção 1: pagamento em n parcelas iguais;• opção 2: pagamento em 6 parcelas a mais do que na opção 1 e, com isso, o valor de cada parcela se torna R$ 500,00 menor do que o valor da parcela na opção 1.Nas duas opções de pagamento, o valor total a ser pago pelo carro é o mesmo.Qual é a quantidade n de parcelas contidas na opção 1 de pagamento?', '[{"type":"text","content":"Um carro que custa 60 mil reais é comercializado por uma revendedora que oferece duas opções de pagamento, todas sem entrada e sem juros:• opção 1: pagamento em n parcelas iguais;• opção 2: pagamento em 6 parcelas a mais do que na opção 1 e, com isso, o valor de cada parcela se torna R$ 500,00 menor do que o valor da parcela na opção 1.Nas duas opções de pagamento, o valor total a ser pago pelo carro é o mesmo.Qual é a quantidade n de parcelas contidas na opção 1 de pagamento?"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', NULL, 'enem/2025/dia2', 'official', 'annulled', 'published', 'imported', 1);
--> statement-breakpoint
