INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025182, 'enem-2025-d2-azul-shared-177', 2025, 2, 'azul', 177, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'A figura ilustra o projeto visual para confecção de uma medalha comemorativa, com a forma de um cilindro circular reto, de diâmetro 6 cm e espessura 3 mm. A figura ABCD tem a forma de um quadrado e é a base de um prisma que atravessa toda a medalha. A região da medalha externa a esse prisma será cunhada em ouro. Pretende-se cunhar 100 dessas medalhas.Considere 3,1 como valor aproximado para p.Qual é o volume de ouro, em centímetro cúbico, necessário para a confecção dessas medalhas?', '[{"type":"text","content":"A figura ilustra o projeto visual para confecção de uma medalha comemorativa, com a forma de um cilindro circular reto, de diâmetro 6 cm e espessura 3 mm."},{"type":"image","content":"/enem/2025/dia2/question-177.png"},{"type":"text","content":"A figura ABCD tem a forma de um quadrado e é a base de um prisma que atravessa toda a medalha. A região da medalha externa a esse prisma será cunhada em ouro. Pretende-se cunhar 100 dessas medalhas.Considere 3,1 como valor aproximado para p.Qual é o volume de ouro, em centímetro cúbico, necessário para a confecção dessas medalhas?"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-177.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
