INSERT INTO `questions` (`id`, `external_id`, `year`, `exam_day`, `booklet`, `official_number`, `language`, `area`, `topic`, `statement`, `content_json`, `support_text`, `source_label`, `source_url`, `image_key`, `asset_bundle_key`, `difficulty`, `answer_status`, `status`, `review_status`, `taxonomy_version`) VALUES (2025185, 'enem-2025-d2-azul-shared-180', 2025, 2, 'azul', 180, NULL, 'Matemática', 'Prova oficial ENEM 2025', 'Quatro amigos, cada um com 100 moedas, criaram um jogo, no qual cada um assume uma das quatro posições, 1, 2, 3 ou 4, indicadas na figura, e nela permanece até o final. O desenvolvimento do jogo se dá em rodadas e, em todas elas, cada jogador transfere e recebe uma quantidade de moedas, da seguinte maneira:• o jogador na posição 1 transfere 1 moeda para o jogador na posição 2;• o jogador na posição 2 transfere 2 moedas para o jogador na posição 3;• o jogador na posição 3 transfere 3 moedas para o jogador na posição 4;• o jogador na posição 4 transfere 4 moedas para o jogador na posição 1, completando a rodada.Ao final da rodada n, qual é a expressão algébrica que representa o número de moedas do jogador na posição 1?', '[{"type":"text","content":"Quatro amigos, cada um com 100 moedas, criaram um jogo, no qual cada um assume uma das quatro posições, 1, 2, 3 ou 4, indicadas na figura, e nela permanece até o final."},{"type":"image","content":"/enem/2025/dia2/question-180.png"},{"type":"text","content":"O desenvolvimento do jogo se dá em rodadas e, em todas elas, cada jogador transfere e recebe uma quantidade de moedas, da seguinte maneira:• o jogador na posição 1 transfere 1 moeda para o jogador na posição 2;• o jogador na posição 2 transfere 2 moedas para o jogador na posição 3;• o jogador na posição 3 transfere 3 moedas para o jogador na posição 4;• o jogador na posição 4 transfere 4 moedas para o jogador na posição 1, completando a rodada.Ao final da rodada n, qual é a expressão algébrica que representa o número de moedas do jogador na posição 1?"}]', NULL, 'INEP · ENEM 2025 · 2º dia · Caderno 7 azul', 'https://download.inep.gov.br/enem/provas_e_gabaritos/2025_PV_impresso_D2_CD7.pdf', '/enem/2025/dia2/question-180.png', 'enem/2025/dia2', 'official', 'valid', 'published', 'imported', 1);
--> statement-breakpoint
